[DataContractAttribute,
SysOperationContractProcessing(classStr(ETGFixedAssetRevaluationProposalUIBuilder)),
  SysOperationGroupAttribute('Group1', "Journal", '2'),
    SysOperationGroupAttribute('Group2', "Fixed assets", '3')]
Public final class ETGFixedAssetRevaluationContract implements SysOperationValidatable
{
    TransDate                   toDate;
    CurrentOperationsTax        postingLayer;
    LedgerJournalNameId         ledgerJournalNameId;
    Str                         assetId;
    AssetGroupId                assetGroupId;

}

Method.Source:
[DataMember, SysOperationGroupMemberAttribute('Group1'), SysOperationDisplayOrderAttribute('1')]
public CurrentOperationsTax parmPostingLayer(CurrentOperationsTax _postingLayer = postingLayer)
{
    postingLayer = _postingLayer;
    return  postingLayer;
}

[DataMember,SysOperationLabel("@ETG:NameOfJournal"), SysOperationGroupMemberAttribute('Group1'), SysOperationDisplayOrderAttribute('2')]
public LedgerJournalNameId parmLedgerJournalNameId(LedgerJournalNameId _ledgerJournalNameId = ledgerJournalNameId)
{
    ledgerJournalNameId = _ledgerJournalNameId;
    return ledgerJournalNameId;
}

[DataMember, SysOperationLabel("@ETG:FixedAssetNumber"), SysOperationGroupMemberAttribute('Group2'), SysOperationDisplayOrderAttribute('1')]
public str parmAssetId(str _assetId = assetId)
{
    assetId = _assetId;
    return assetId;
}

[DataMember, SysOperationGroupMemberAttribute('Group2'), SysOperationDisplayOrderAttribute('2')]
public AssetGroupId parmAssetGroupId(AssetGroupId _assetGroupId = assetGroupId)
{
    assetGroupId = _assetGroupId;
    return assetGroupId;
}

public boolean validate()
{
    boolean isValid = true;

    if(!this.parmAssetId() && !this.parmAssetGroupId())
    {
        isValid = checkFailed("@ETG:AssetIdOrAssetgroup");
    }
    return isValid;
}
